pattern.example:

// BAD: Potential null pointer exception
const user = getUser();
console.log(user.name); // Will crash if user is null

// GOOD: Proper null checking
const user = getUser();
if (user) {
  console.log(user.name);
}


// BAD: Unhandled promise rejection
async function fetchData() {
  const response = await fetch('/api/data');
  // No error handling
}

// GOOD: Proper error handling
async function fetchData() {
  try {
    const response = await fetch('/api/data');
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    return await response.json();
  } catch (error) {
    console.error('Failed to fetch data:', error);
    throw error;
  }
}


// BAD: Infinite loop
while (true) {
  // No break condition
}

// GOOD: Proper termination
let count = 0;
while (count < 10) {
  count++;
}


// BAD: Memory leak in React component
useEffect(() => {
  const interval = setInterval(() => {
    // Do something
  }, 1000);
  // Missing cleanup
}, []);

// GOOD: Proper cleanup
useEffect(() => {
  const interval = setInterval(() => {
    // Do something
  }, 1000);
  return () => clearInterval(interval);
}, []);


// BAD: Race condition
let counter = 0;
function increment() {
  counter++; // Not atomic
}

// GOOD: Use proper synchronization
let counter = 0;
const lock = new Mutex();
async function increment() {
  const release = await lock.acquire();
  try {
    counter++;
  } finally {
    release();
  }
}


// BAD: Component re-renders on every parent update
function MyComponent({ data }) {
  return <div>{data}</div>;
}

// GOOD: Memoized component
const MyComponent = React.memo(({ data }) => {
  return <div>{data}</div>;
});


// BAD: O(n²) nested loop
function findDuplicates(arr: number[]): number[] {
  const duplicates: number[] = [];
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      if (arr[i] === arr[j]) {
        duplicates.push(arr[i]);
      }
    }
  }
  return duplicates;
}

// GOOD: O(n) using Set
function findDuplicates(arr: number[]): number[] {
  const seen = new Set<number>();
  const duplicates: number[] = [];
  for (const num of arr) {
    if (seen.has(num)) {
      duplicates.push(num);
    } else {
      seen.add(num);
    }
  }
  return duplicates;
}


// BAD: Redundant computation
function processUsers(users: User[]) {
  const activeUsers = users.filter(u => u.isActive);
  const activeUserCount = activeUsers.length; // Recalculating
  const activeUserNames = activeUsers.map(u => u.name); // Recalculating
}

// GOOD: Compute once
function processUsers(users: User[]) {
  const activeUsers = users.filter(u => u.isActive);
  const activeUserCount = activeUsers.length;
  const activeUserNames = activeUsers.map(u => u.name);
}


// BAD: Unnecessary API calls
function getUserData(userId: string) {
  return fetch(`/api/users/${userId}`); // Called repeatedly
}

// GOOD: Cache API responses
const userCache = new Map<string, Promise<User>>();
function getUserData(userId: string) {
  if (!userCache.has(userId)) {
    userCache.set(userId, fetch(`/api/users/${userId}`).then(r => r.json()));
  }
  return userCache.get(userId)!;
}


// BAD: Ambiguous names
const x = 10;
const data = getUser();
const temp = process(input);

// GOOD: Descriptive names
const userCount = 10;
const userData = getUser();
const processedResult = process(input);


// BAD: Inconsistent naming
const user_name = "John";
const userName = "Jane";
const USER_NAME = "Bob";

// GOOD: Consistent naming (camelCase for variables)
const userName = "John";
const userAge = 30;
const isActive = true;


// BAD: Magic numbers
if (status === 2) {
  // What does 2 mean?
}

// GOOD: Named constants
const STATUS_ACTIVE = 2;
if (status === STATUS_ACTIVE) {
  // Clear meaning
}


// BAD: Boolean without prefix
const active = true;
const valid = false;

// GOOD: Boolean with proper prefix
const isActive = true;
const isValid = false;
const hasPermission = true;


// BAD: Using let for never-reassigned variable
let name = "John";
console.log(name);

// GOOD: Using const for never-reassigned variable
const name = "John";
console.log(name);


// BAD: Unused variable
function process(data: string) {
  const unused = "something";
  return data;
}

// GOOD: Remove unused variables
function process(data: string) {
  return data;
}
